VALUES
  ('optician-moex-00119', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於使用螢光染色評估硬式隱形眼鏡，下列敘述何者錯誤？', '["出現Apicalbearing染色，可將鏡片基弧縮小改善", "出現Apicalclearance染色，可加大鏡片直徑改善", "出現Thedumbbell-shaped染色，表示角膜有高散光", "出現Alignment染色，表示鏡片輕微接觸角膜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00120', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於軟式隱形眼鏡的驗配，下列何者錯誤？', '["傳統上，基弧（basecurve）在調整貼合度上是需要修改的主要參數", "使用越薄的高含水鏡片，改變基弧對於影響貼合度的效果越明顯", "當鏡片比較鬆的時候，可以嘗試把基弧變陡（steep）", "當鏡片比較緊的時候，可以嘗試把基弧變較平（flat）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
